import numpy as np

class Generator:
    def __init__(self, latent_dim: int, output_dim: int, hidden_dim: int = 32):
        self.latent_dim = latent_dim
        self.output_dim = output_dim
        self.hidden_dim = hidden_dim
        self.params = self._init_params()

    def _init_params(self):
        return {
            'W1': np.random.randn(self.latent_dim, self.hidden_dim) * 0.1,
            'b1': np.zeros(self.hidden_dim),
            'W2': np.random.randn(self.hidden_dim, self.output_dim) * 0.1,
            'b2': np.zeros(self.output_dim)
        }

    def forward(self, z: np.ndarray) -> np.ndarray:
        h = np.maximum(0, z @ self.params['W1'] + self.params['b1'])
        out = np.tanh(h @ self.params['W2'] + self.params['b2'])
        return out

    def generate(self, n_samples: int) -> np.ndarray:
        z = np.random.randn(n_samples, self.latent_dim)
        return self.forward(z)

class Discriminator:
    def __init__(self, input_dim: int, hidden_dim: int = 32):
        self.input_dim = input_dim
        self.hidden_dim = hidden_dim
        self.params = self._init_params()

    def _init_params(self):
        return {
            'W1': np.random.randn(self.input_dim, self.hidden_dim) * 0.1,
            'b1': np.zeros(self.hidden_dim),
            'W2': np.random.randn(self.hidden_dim, 1) * 0.1,
            'b2': np.zeros(1)
        }

    def forward(self, x: np.ndarray) -> np.ndarray:
        h = np.maximum(0, x @ self.params['W1'] + self.params['b1'])
        logit = h @ self.params['W2'] + self.params['b2']
        return 1 / (1 + np.exp(-logit))

import numpy as np

def discriminator_loss(D_real: np.ndarray, D_fake: np.ndarray) -> float:
    eps = 1e-8
    loss_real = -np.mean(np.log(D_real + eps))
    loss_fake = -np.mean(np.log(1 - D_fake + eps))
    return loss_real + loss_fake

def generator_loss_saturating(D_fake: np.ndarray) -> float:
    eps = 1e-8
    return np.mean(np.log(1 - D_fake + eps))

def generator_loss_nonsaturating(D_fake: np.ndarray) -> float:
    eps = 1e-8
    return -np.mean(np.log(D_fake + eps))

def wasserstein_critic_loss(C_real: np.ndarray, C_fake: np.ndarray) -> float:
    return np.mean(C_fake) - np.mean(C_real)

import numpy as np
from typing import Dict

class ModeCollapseDetector:
    def __init__(self, generator):
        self.generator = generator

    def compute_sample_diversity(self, n_samples: int = 500) -> Dict:
        samples = self.generator.generate(n_samples)

        distances = []
        n_check = min(100, n_samples)
        for i in range(n_check):
            for j in range(i + 1, n_check):
                dist = np.linalg.norm(samples[i] - samples[j])
                distances.append(dist)

        distances = np.array(distances)

        return {
            'mean_distance': float(np.mean(distances)),
            'std_distance': float(np.std(distances)),
            'min_distance': float(np.min(distances)),
            'max_distance': float(np.max(distances))
        }

    def count_unique_samples(self, n_samples: int = 500, precision: int = 2) -> int:
        samples = self.generator.generate(n_samples)
        rounded = np.round(samples, precision)
        unique = set(tuple(s) for s in rounded)
        return len(unique)

    def compute_nearest_neighbor_distance(self, n_samples: int = 500) -> np.ndarray:
        samples = self.generator.generate(n_samples)
        nn_distances = []

        for i in range(len(samples)):
            min_dist = float('inf')
            for j in range(len(samples)):
                if i != j:
                    dist = np.linalg.norm(samples[i] - samples[j])
                    min_dist = min(min_dist, dist)
            nn_distances.append(min_dist)

        return np.array(nn_distances)

    def is_mode_collapsed(self, n_samples: int = 500, diversity_threshold: float = 0.1) -> bool:
        diversity = self.compute_sample_diversity(n_samples)
        unique_ratio = self.count_unique_samples(n_samples) / n_samples

        return diversity['mean_distance'] < diversity_threshold or unique_ratio < 0.5

class MockGenerator:
    def __init__(self, collapsed: bool = False):
        self.collapsed = collapsed

    def generate(self, n: int) -> np.ndarray:
        if self.collapsed:
            return np.ones((n, 5)) + np.random.randn(n, 5) * 0.01
        return np.random.randn(n, 5)
